// Add menu item for file upload
add_menu_page( 'User File Upload', 'File Upload', 'manage_options', 'user-file-upload', 'user_file_uploader' );

function user_file_uploader() {
    // Check if form is submitted
    if (isset($_POST['submit'])) {
        // Define allowed file types
        $allowed_types = array('image/jpeg', 'image/png', 'application/pdf', 'application/msword');
        
        // Check if file type is allowed
        if (in_array($_FILES['uploadedfile']['type'], $allowed_types)) {
            // Define upload directory and filename
            $target = WP_CONTENT_DIR . '/uploads/user-files/' . basename($_FILES['uploadedfile']['name']);
            
            // Check if file already exists
            if (file_exists($target)) {
                echo '<p>File with the same name already exists. Please choose a different name.</p>';
            } else {
                // Move uploaded file to uploads directory
                move_uploaded_file($_FILES['uploadedfile']['tmp_name'], $target);
                
                echo '<p>File uploaded successfully.</p>';
            }
        } else {
            echo '<p>Invalid file type. Only JPEG, PNG and PDF files are allowed.</p>';
        }
    }
    
    // Display upload form
    ?>
    <form action="" method="post" enctype="multipart/form-data">
        <input type="file" name="uploadedfile" id="uploadedfile" value="" />
        <input type="submit" name="submit" id="submit" value="Upload File" />
    </form>
    <?php
}